B.a_2=new A.m(B.x,"Bekleme turu neden \xf6nemlidir?",'ATC trafi\u011fi d\xfczenlemek veya hava ko\u015fullar\u0131n\u0131n iyile\u015fmesini beklemek i\xe7in u\xe7aklar\u0131 "hold" (bekleme turu) komutuyla belirli bir b\xf6lgede u\xe7urmaktad\u0131r. Hold talimat\u0131 birden fazla kritik bilgi i\xe7erir ve pilot bunlar\u0131n hepsini do\u011fru anlamal\u0131d\u0131r.',null,null,null)
