B.a9h=s(["Direct source of good lighting","Inspection aids such as mirrors","Complete disassembly of the aircraft","Surface cleaning"],t.s)
B.aj1=new A.x(-71,B.N,602,"Which of the following is NOT necessarily required for a Detailed Inspection?",B.a9h,2,B.q,null,null,null)
B.abO=s(["An entire aircraft at once","The aircraft's documentation","A specific item, installation, or assembly","Only the exterior of the aircraft"],t.s)
