B.UC=new A.m(B.x,"Modern u\xe7aklar karma\u015f\u0131k enstr\xfcman sistemlerine dayan\u0131r","Aviyonik kelime bilgisi okuma anlama, kelime doldurma ve c\xfcmle tamamlama sorular\u0131nda kar\u015f\u0131n\u0131za \xe7\u0131kar. Her enstr\xfcman\u0131n ne yapt\u0131\u011f\u0131n\u0131 ve k\u0131lavuzlarda nas\u0131l tan\u0131mland\u0131\u011f\u0131n\u0131 anlamak orta ve ileri d\xfczey i\xe7in \u015fartt\u0131r.",null,null,null)
B.Yx=new A.m(B.v,"\u2708\ufe0f Temel U\xe7u\u015f Enstr\xfcmanlar\u0131","**ADI (Attitude Director Indicator)** \u2014 shows pitch and bank\n**HSI (Horizontal Situation Indicator)** \u2014 combined heading + navigation\n**VSI (Vertical Speed Indicator)** \u2014 rate of climb/descent in feet per minute\n**ASI (Airspeed Indicator)** \u2014 shows IAS in knots\n**Altimeter** \u2014 shows altitude using static pressure\n**Turn & Slip Indicator** \u2014 shows rate of turn and coordination",null,null,null)
