B.XN=new A.m(B.an,"\u2708\ufe0f S\u0131nav \u0130pucu",'U\xe7u\u015f plan\u0131 sorular\u0131 genellikle \u015funlara odaklan\u0131r:\n\u2022 **U\xe7ak tipi / iz t\xfcrb\xfclanss\u0131 kategorisi** \u2014 ICAO u\xe7ak tan\u0131mlay\u0131c\u0131lar\u0131n\u0131 bilin\n\u2022 **EET** (Tahmini Ge\xe7en S\xfcre) vs. **ETA** (Tahmini Var\u0131\u015f Saati)\n\u2022 **Yedek havaliman\u0131** gereksinimleri \u2014 ne zaman gerekli?\n\u2022 Alan 18\'deki **PBN** (Performansa Dayal\u0131 Seyrs\xfcsefer) kodlar\u0131\n\nYayg\u0131n tuzak: "EOBT" = Tahmini Blok Ayr\u0131l\u0131\u015f Saati (geri itme ba\u015flad\u0131\u011f\u0131nda), KALKI\u015e saati de\u011fil.',null,null,null)
