B.We=new A.m(B.x,"Prosed\xfcr belgeleri teknik bilgi ile doludur","Standart Enstr\xfcman Kalk\u0131\u015flar\u0131 (SID) ve Standart Terminal Vari\u015f Rotalar\u0131 (STAR), irtifalar, h\u0131zlar, ara noktalar ve k\u0131s\u0131tlamalar i\xe7eren belgelenmi\u015f prosed\xfcrlerdir. \u0130leri d\xfczey okuma anlama sorular\u0131 bu belgelerden al\u0131nt\u0131 kullan\u0131r ve kesin yorumlama gerektirir.",null,null,null)
B.WJ=new A.m(B.v,"\ud83d\udeeb SID \u2014 Kalk\u0131\u015f Prosed\xfcr\xfc",'A SID (Standart Enstr\xfcman Kalk\u0131\u015f Prosed\xfcr\xfc) \u015funlar\u0131 sa\u011flar:\n\u2022 Pistden en-route yap\u0131s\u0131na rotalama\n\u2022 \u0130rtifa k\u0131s\u0131tlamalar\u0131 ("at or above 3,000 ft at waypoint TURPO")\n\u2022 H\u0131z k\u0131s\u0131tlamalar\u0131 ("250 KIAS below 10,000 ft")\n\u2022 Ge\xe7i\u015f kodlar\u0131 (RNAV, geleneksel)\n\n**\u0130rtifa kodlamas\u0131:**\n\u2022 **"A030+"** = 3.000 ft veya \xfczeri\n\u2022 **"A050-"** = 5.000 ft veya alt\u0131\n\u2022 **"A060B080"** = 6.000 ile 8.000 ft aras\u0131\n\u2022 **"S220"** = 220 KIAS veya alt\u0131nda h\u0131z koru',null,null,null)
B.VY=new A.m(B.v,"\ud83d\udeec STAR \u2014 Var\u0131\u015f Prosed\xfcr\xfc",'Bir STAR (Standart Terminal Vari\u015f Rotas\u0131) \u015funlar\u0131 sa\u011flar:\n\u2022 en-route yap\u0131s\u0131ndan terminal alan\u0131na/yakla\u015fmaya rotalama\n\u2022 H\u0131z azaltma profili\n\u2022 IAF noktas\u0131na (Ba\u015flang\u0131\xe7 Yakla\u015fma Noktas\u0131) ge\xe7i\u015f\n\n**Yayg\u0131n STAR terminolojisi:**\n\u2022 **IAF** \u2014 Ba\u015flang\u0131\xe7 Yakla\u015fma Noktas\u0131\n\u2022 **IF** \u2014 Orta Nokta\n\u2022 **FAF** \u2014 Son Yakla\u015fma Noktas\u0131\n\u2022 **MAP** \u2014 Yanl\u0131\u015f Yakla\u015fma Karar Noktas\u0131\n\u2022 **Published hold** \u2014 prosed\xfcrdeki bekleme d\xf6ng\xfcs\xfc\n\u2022 **"Expect vectors"** \u2014 ATC radar y\xf6nlendirmesi verecek',null,null,null)
B.PT=new A.Z("At or above 6,000 feet at TURPO waypoint before turning left to intercept the final approach course.","Final yakla\u015fma pistine girilmeden \xf6nce TURPO noktas\u0131nda 6.000 ft veya \xfczerinde olmak zorunludur.","At or above")
B.Pw=new A.Z("Maintain 250 knots or less until 10 DME from the airport.","Havaliman\u0131ndan 10 DME mesafeye kadar 250 knot veya daha d\xfc\u015f\xfck h\u0131z koruyun.","Maintain 250 knots or less")
B.a4A=s([B.PT,B.Pw],t.l)
B.ZC=new A.m(B.G,"Prosed\xfcr Dili",null,B.a4A,null,null)
B.UI=new A.m(B.an,"\u2708\ufe0f S\u0131nav \u0130pucu",'Prosed\xfcr belgelerinde "At or above" / "at or below":\n\u2022 "A030+" = 3.000 ft veya **\xfczeri** (art\u0131 i\u015fareti = daha y\xfcksek)\n\u2022 "A050-" = 5.000 ft veya **alt\u0131** (eksi i\u015fareti = daha al\xe7ak)\n\nBir ara noktada hem h\u0131z hem irtifa k\u0131s\u0131tlamas\u0131 varsa, **her ikisine** e\u015f zamanl\u0131 uyulmal\u0131d\u0131r.\n\nBir STAR\'daki "Expect vectors", ATC\'nin her zaman vekt\xf6r verece\u011fi anlam\u0131na gelmez \u2014 pilot beklemelidir (vekt\xf6r verilmezse yay\u0131mlanm\u0131\u015f prosed\xfcr\xfc uygulay\u0131n).',null,null,null)
