B.a1A=s(["Both are turned ON","One is ON and one is OFF","Both are turned OFF","The position does not matter"],t.s)
B.akG=new A.x(-101,B.N,607,"During wet motoring, what is the position of the ignition systems?",B.a1A,2,B.p,null,null,null)
B.a4Q=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
