B.X7=new A.m(B.x,"Tehlikeli madde fark\u0131ndal\u0131\u011f\u0131 neden zorunludur","ICAO Technical Instructions ve IATA DGR (Dangerous Goods Regulations) uyar\u0131nca kabin ekibi tehlikeli madde tan\u0131mlama ve bildirme konusunda e\u011fitim almal\u0131d\u0131r.\n\nTehlikeli maddeler u\xe7ak g\xfcvenli\u011fine ciddi tehdit olu\u015fturabilir. Do\u011fru tan\u0131mlama ve h\u0131zl\u0131 bildirim \xe7ok \xf6nemlidir.",null,null,null)
