B.Wg=new A.m(B.x,"Neden do\u011fru ar\u0131za kayd\u0131 kritiktir","Teknik Log (Aircraft Technical Log) ve ar\u0131za raporlar\u0131 **yasal belgelerdir**. Bir ar\u0131zan\u0131n yanl\u0131\u015f veya eksik kaydedilmesi u\xe7u\u015f g\xfcvenli\u011fini tehlikeye atar ve ciddi yasal sonu\xe7lar do\u011furur.\n\nDo\u011fru ar\u0131za kayd\u0131: nedeni a\xe7\u0131k\xe7a belirtir, yap\u0131lan i\u015flemi do\u011fru fiillerle anlat\u0131r ve yetkili onay\u0131 i\xe7erir.",null,null,null)
B.ZZ=new A.m(B.v,"\u270f\ufe0f Ar\u0131za Raporu Yaz\u0131m Kurallar\u0131",'**Ar\u0131za tan\u0131m\u0131nda kullan\u0131lan fiiller:**\n\u2022 found \u2014 bulundu (pasif ke\u015fif)\n\u2022 observed \u2014 g\xf6zlemlendi\n\u2022 reported \u2014 raporland\u0131 / bildirildi\n\u2022 indicated \u2014 g\xf6sterge g\xf6sterdi\n\u2022 failed \u2014 ar\u0131zaland\u0131\n\u2022 leaked \u2014 s\u0131zd\u0131\n\n**D\xfczeltici faaliyet fiilleri:**\n\u2022 replaced \u2014 de\u011fi\u015ftirildi\n\u2022 inspected \u2014 muayene edildi\n\u2022 cleaned and reinstalled \u2014 temizlendi ve yeniden tak\u0131ld\u0131\n\u2022 tested \u2014 test edildi\n\u2022 adjusted \u2014 ayarland\u0131\n\u2022 deferred in accordance with MEL \u2014 MEL kapsam\u0131nda ertelendi\n\n**Kapan\u0131\u015f ifadesi:**\n\u2022 "Aircraft released to service" / "Component released serviceable"\n\u2022 "Certified in accordance with AMM [chapter]"',null,null,null)
B.Qc=new A.Z("Defect: No. 2 engine oil pressure found low during post-flight inspection. Action: Checked oil level \u2014 found 2 qts low. Added oil per AMM 79-00-00. Oil pressure normal on ground run.","Ar\u0131za: U\xe7u\u015f sonras\u0131 muayenede 2 no'lu motor ya\u011f bas\u0131nc\u0131 d\xfc\u015f\xfck bulundu. \u0130\u015flem: Ya\u011f seviyesi kontrol edildi \u2014 2 litre eksik bulundu. AMM 79-00-00'a g\xf6re ya\u011f ilave edildi. Yer \xe7al\u0131\u015ft\u0131rmas\u0131nda ya\u011f bas\u0131nc\u0131 normal.","found \u2026 Added \u2026 per AMM")
B.NQ=new A.Z("Defect deferred in accordance with MEL item 29-01. Aircraft released to service. Next required action within 3 flight days.","Ar\u0131za MEL madde 29-01 kapsam\u0131nda ertelendi. U\xe7ak servise al\u0131nd\u0131. Bir sonraki gerekli i\u015flem 3 u\xe7u\u015f g\xfcn\xfc i\xe7inde.","deferred in accordance with MEL \u2026 released to service")
